-- 3. EXPANDED DEFAULT ESTIMATE TEMPLATES -------------------------------------
-- Read-only reference data (template items carry names+units, not FKs), so a
-- delete + re-insert of the is_default set never touches a master's own templates.
DELETE FROM estimate_templates WHERE is_default = TRUE;


